int maximum(int a, int b, int c) {
    int k;
    if (a <= b)
        k = b;
    else
        k = a;

    if (k <= c)
        return c;
    else
        return k;
}

void needle_kernel1(int* referrence,
                    int* matrix_cuda,
                    int* output_buffer,
                    int cols,
                    int penalty,
                    int i,
                    int block_width,
                    int worksize,
                    int offset_r,
                    int offset_c)
{
    int bx = get_global_id(0) / BLOCK_SIZE;
    int tx = get_global_id(0) % BLOCK_SIZE;

    int b_index_x = bx;
    int b_index_y = i - 1 - bx;

    int base_index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;
    int index   = base_index + tx + (cols + 1);
    int index_n   = base_index + tx + (1);
    int index_w   = base_index + (cols);
    int index_nw =  base_index;

    // Declare local memory arrays explicitly
    int temp_local[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int ref_local[BLOCK_SIZE * BLOCK_SIZE];

    // Load reference block
    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        ref_local[ty * BLOCK_SIZE + tx] = referrence[index + cols * ty];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (tx == 0)
        temp_local[0] = matrix_cuda[index_nw];

    temp_local[(tx + 1) * (BLOCK_SIZE + 1)] = matrix_cuda[index_w + cols * tx];
    temp_local[tx + 1] = matrix_cuda[index_n];

    barrier(CLK_LOCAL_MEM_FENCE);

    // First diagonal pass
    for (int m = 0; m < BLOCK_SIZE; m++) {
        if (tx <= m) {
            int t_index_x = tx + 1;
            int t_index_y = m - tx + 1;

            int val_diag = temp_local[(t_index_y - 1) * (BLOCK_SIZE + 1) + (t_index_x - 1)] + ref_local[(t_index_y - 1) * BLOCK_SIZE + (t_index_x - 1)];
            int val_left = temp_local[(t_index_y) * (BLOCK_SIZE + 1) + (t_index_x - 1)] - penalty;
            int val_up   = temp_local[(t_index_y - 1) * (BLOCK_SIZE + 1) + (t_index_x)] - penalty;

            temp_local[t_index_y * (BLOCK_SIZE + 1) + t_index_x] = maximum(val_diag, val_left, val_up);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Second diagonal pass
    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        if (tx <= m) {
            int t_index_x = tx + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - tx;

            int val_diag = temp_local[(t_index_y - 1) * (BLOCK_SIZE + 1) + (t_index_x - 1)] + ref_local[(t_index_y - 1) * BLOCK_SIZE + (t_index_x - 1)];
            int val_left = temp_local[(t_index_y) * (BLOCK_SIZE + 1) + (t_index_x - 1)] - penalty;
            int val_up   = temp_local[(t_index_y - 1) * (BLOCK_SIZE + 1) + (t_index_x)] - penalty;

            temp_local[t_index_y * (BLOCK_SIZE + 1) + t_index_x] = maximum(val_diag, val_left, val_up);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Write back
    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        matrix_cuda[index + ty * cols] = temp_local[(ty + 1) * (BLOCK_SIZE + 1) + (tx + 1)];
    }
}

